import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Allocate a buffer with a dynamic size based on the input length
        byte[] buffer = new byte[Math.min(name.length(), 10)];

        // Copy bytes from the input string to the buffer
        System.arraycopy(name.getBytes(), 0, buffer, 0, buffer.length);

        System.out.println("Hello, " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
